import React, { useEffect, useState } from 'react';
import {
  Button,
  Checkbox,
  FormRowCol,
  Input,
  Modal,
  Select,
  dispatchAppToast,
} from '@linm-soft/common-components';
import { catalogUiSchemaService } from '../../../services/master/catalogUiSchemaService';
import { useAppDispatch } from '../../../store/hooks';
import type { CatalogUiField, CatalogUiGridConfig, CatalogUiSchema } from '../../../types/catalogUiSchema';
import { resolveApiErrorMessage } from '../../../utils/resolveApiErrorMessage';
import styles from '../../../styles/erpPage.module.css';
import schemaStyles from './CatalogUiSchemaEditorModal.module.css';

export interface CatalogUiSchemaEditorModalProps {
  testIdPrefix: string;
  catalogKind: string;
  isOpen: boolean;
  onClose: () => void;
  onSaved: (schema: CatalogUiSchema) => void;
}

const HEIGHT_MODE_OPTIONS = [
  { value: 'auto', label: 'Auto' },
  { value: 'fixed', label: 'Fixed' },
];

const DETAIL_GRID_STICKY_HEADER = true;

function withDetailGridStickyHeader(schema: CatalogUiSchema): CatalogUiSchema {
  const detail = schema.tableConfig?.detailGrid;
  if (!detail || detail.stickyHeader === DETAIL_GRID_STICKY_HEADER) {
    return schema;
  }
  return {
    ...schema,
    tableConfig: {
      ...(schema.tableConfig ?? {}),
      detailGrid: { ...detail, stickyHeader: DETAIL_GRID_STICKY_HEADER },
    },
  };
}

function patchField(
  fields: CatalogUiField[],
  key: string,
  patch: Partial<Pick<CatalogUiField, 'list' | 'lookup' | 'proposal'>>,
): CatalogUiField[] {
  return fields.map(f => {
    if (f.key !== key) return f;
    return {
      ...f,
      ...(patch.list != null ? { list: patch.list } : {}),
      ...(patch.lookup != null ? { lookup: patch.lookup } : {}),
      ...(patch.proposal != null ? { proposal: patch.proposal } : {}),
    };
  });
}

type GridConfigBlockProps = {
  title: string;
  gridKey: 'masterGrid' | 'detailGrid';
  config: CatalogUiGridConfig | undefined;
  onPatch: (patch: Partial<CatalogUiGridConfig>) => void;
};

const GridConfigBlock: React.FC<GridConfigBlockProps> = ({
  title,
  gridKey,
  config,
  onPatch,
}) => {
  const lockStickyHeader = gridKey === 'detailGrid';

  return (
    <div className={schemaStyles.gridBlock} data-testid={`grid-config-${gridKey}`}>
      <div className={schemaStyles.gridBlockTitle}>
        {title}
        {lockStickyHeader ? (
          <span className={schemaStyles.gridStickyHint}> · sticky header (luôn bật)</span>
        ) : null}
      </div>
      <FormRowCol cols={4} data-testid={`${gridKey}-row-col`}>
        <FormRowCol.Item label="Height mode">
          <Select
            value={config?.heightMode ?? 'auto'}
            options={HEIGHT_MODE_OPTIONS}
            onChange={e => onPatch({ heightMode: e.target.value as 'auto' | 'fixed' })}
          />
        </FormRowCol.Item>
        <FormRowCol.Item label="Height">
          <Input
            value={config?.height ?? ''}
            placeholder={gridKey === 'masterGrid' ? 'vd: 420px' : 'vd: 320px'}
            onChange={e => onPatch({ height: e.target.value || null })}
          />
        </FormRowCol.Item>
        <FormRowCol.Item variant="control" hidden={lockStickyHeader}>
          <Checkbox
            label="sticky header"
            checked={config?.stickyHeader ?? true}
            onChange={e => onPatch({ stickyHeader: e.target.checked })}
          />
        </FormRowCol.Item>
        <FormRowCol.Item variant="control">
          <Checkbox
            label="resizable columns"
            checked={config?.resizableColumns ?? true}
            onChange={e => onPatch({ resizableColumns: e.target.checked })}
          />
        </FormRowCol.Item>
      </FormRowCol>
    </div>
  );
};

export const CatalogUiSchemaEditorModal: React.FC<CatalogUiSchemaEditorModalProps> = ({
  testIdPrefix,
  catalogKind,
  isOpen,
  onClose,
  onSaved,
}) => {
  const dispatch = useAppDispatch();
  const [draft, setDraft] = useState<CatalogUiSchema | null>(null);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    if (!isOpen) return;
    let cancelled = false;
    setLoading(true);
    catalogUiSchemaService
      .get(catalogKind, true)
      .then(data => {
        if (!cancelled) setDraft(withDetailGridStickyHeader(data));
      })
      .catch(err => {
        if (!cancelled) {
          dispatchAppToast(dispatch, {
            message: resolveApiErrorMessage(err, 'Lỗi tải cấu hình'),
            type: 'error',
          });
        }
      })
      .finally(() => {
        if (!cancelled) setLoading(false);
      });
    return () => { cancelled = true; };
  }, [isOpen, catalogKind, dispatch]);

  const editableFields = draft?.fields.filter(f => f.configurable !== false) ?? [];
  const isAccountsConfig = draft?.catalogKind === 'accounts';

  const updateList = (key: string, visible: boolean, width?: string) => {
    setDraft(prev => {
      if (!prev) return prev;
      return {
        ...prev,
        fields: patchField(prev.fields, key, {
          list: {
            visible,
            order: prev.fields.find(f => f.key === key)?.list?.order ?? 0,
            width: width ?? prev.fields.find(f => f.key === key)?.list?.width ?? undefined,
            variant: prev.fields.find(f => f.key === key)?.list?.variant ?? undefined,
          },
        }),
      };
    });
  };

  const updateLookup = (key: string, visible: boolean, width?: string, variant?: string) => {
    setDraft(prev => {
      if (!prev) return prev;
      const cur = prev.fields.find(f => f.key === key);
      return {
        ...prev,
        fields: patchField(prev.fields, key, {
          lookup: {
            visible,
            order: cur?.lookup?.order ?? 0,
            width: width ?? cur?.lookup?.width ?? undefined,
            variant: variant ?? cur?.lookup?.variant ?? undefined,
          },
        }),
      };
    });
  };

  const updateProposal = (key: string, editable: boolean) => {
    setDraft(prev => {
      if (!prev) return prev;
      const cur = prev.fields.find(f => f.key === key);
      return {
        ...prev,
        fields: patchField(prev.fields, key, {
          proposal: {
            editable,
            order: cur?.proposal?.order ?? 0,
          },
        }),
      };
    });
  };

  const patchGridConfig = (
    gridKey: 'masterGrid' | 'detailGrid',
    patch: Partial<CatalogUiGridConfig>,
  ) => {
    setDraft(prev => {
      if (!prev) return prev;
      const current = prev.tableConfig?.[gridKey] ?? {};
      const merged = {
        stickyHeader: true,
        heightMode: 'auto' as const,
        height: null,
        resizableColumns: true,
        ...current,
        ...patch,
        ...(gridKey === 'detailGrid' ? { stickyHeader: DETAIL_GRID_STICKY_HEADER } : {}),
      };
      return {
        ...prev,
        tableConfig: {
          ...(prev.tableConfig ?? {}),
          [gridKey]: merged,
        },
      };
    });
  };

  const handleSave = async () => {
    if (!draft) return;
    setSaving(true);
    try {
      const draftToSave = withDetailGridStickyHeader(draft);
      const saved = await catalogUiSchemaService.save(catalogKind, {
        schemaVersion: draftToSave.schemaVersion,
        fields: draftToSave.fields.filter(f => f.configurable !== false),
        lookup: draftToSave.lookup,
        list: draftToSave.list,
        hintText: draftToSave.hintText ?? null,
        tableConfig: draftToSave.tableConfig ?? null,
      });
      dispatchAppToast(dispatch, { message: 'Đã lưu cấu hình hiển thị danh mục', type: 'success' });
      onSaved(saved);
      onClose();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: resolveApiErrorMessage(err, 'Lưu cấu hình thất bại'),
        type: 'error',
      });
    } finally {
      setSaving(false);
    }
  };

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title="Cấu hình hiển thị danh mục"
      size="lg"
      fillContent
    >
      <div
        className={[schemaStyles.shell, schemaStyles.shellFill].filter(Boolean).join(' ')}
        data-testid={`${testIdPrefix}-schema-editor`}
      >
        {loading && <p>Đang tải…</p>}
        {!loading && draft && (
          <>
            <div className={schemaStyles.body}>
              <p className={styles.sharedCatalogHint}>
                Chọn cột hiển thị trên danh sách, lookup (form/chứng từ) và trường cho phép đề xuất sửa đổi.
              </p>
              {isAccountsConfig ? (
                <div className={schemaStyles.configSection}>
                  <div className={styles.field}>
                    <label className={styles.label}>Hint header</label>
                    <Input
                      value={draft.hintText ?? ''}
                      placeholder="Nhập mô tả/hint cho Danh mục tài khoản"
                      data-testid={`${testIdPrefix}-schema-hint-text`}
                      onChange={e => setDraft(prev => prev ? { ...prev, hintText: e.target.value } : prev)}
                    />
                  </div>
                  <GridConfigBlock
                    title="Master grid"
                    gridKey="masterGrid"
                    config={draft.tableConfig?.masterGrid}
                    onPatch={patch => patchGridConfig('masterGrid', patch)}
                  />
                  <GridConfigBlock
                    title="Detail grid"
                    gridKey="detailGrid"
                    config={draft.tableConfig?.detailGrid}
                    onPatch={patch => patchGridConfig('detailGrid', patch)}
                  />
                </div>
              ) : null}
              <div className={schemaStyles.detailScroll}>
                <table className={styles.table}>
                  <thead>
                    <tr>
                      <th>Trường</th>
                      <th>List</th>
                      <th>Rộng list</th>
                      <th>Lookup</th>
                      <th>Rộng lookup</th>
                      <th>Đề xuất</th>
                    </tr>
                  </thead>
                  <tbody>
                    {editableFields.map(f => (
                      <tr key={f.key}>
                        <td>
                          <strong>{f.label}</strong>
                          <br />
                          <code className={styles.schemaFieldKey}>{f.key}</code>
                        </td>
                        <td>
                          <Checkbox
                            id={`${testIdPrefix}-schema-list-cb-${f.key}`}
                            aria-label={`Hiển thị ${f.label} trên danh sách`}
                            checked={!!f.list?.visible}
                            data-testid={`${testIdPrefix}-schema-list-${f.key}`}
                            onChange={e => updateList(f.key, e.target.checked)}
                          />
                        </td>
                        <td>
                          <Input
                            value={f.list?.width ?? ''}
                            placeholder="8rem / 1fr"
                            disabled={!f.list?.visible}
                            data-testid={`${testIdPrefix}-schema-list-w-${f.key}`}
                            onChange={e => updateList(f.key, !!f.list?.visible, e.target.value)}
                          />
                        </td>
                        <td>
                          <Checkbox
                            id={`${testIdPrefix}-schema-lookup-cb-${f.key}`}
                            aria-label={`Hiển thị ${f.label} trên lookup`}
                            checked={!!f.lookup?.visible}
                            data-testid={`${testIdPrefix}-schema-lookup-${f.key}`}
                            onChange={e => updateLookup(f.key, e.target.checked)}
                          />
                        </td>
                        <td>
                          <Input
                            value={f.lookup?.width ?? ''}
                            placeholder="5rem"
                            disabled={!f.lookup?.visible}
                            data-testid={`${testIdPrefix}-schema-lookup-w-${f.key}`}
                            onChange={e => updateLookup(f.key, !!f.lookup?.visible, e.target.value)}
                          />
                        </td>
                        <td>
                          <Checkbox
                            id={`${testIdPrefix}-schema-proposal-cb-${f.key}`}
                            aria-label={`Cho phép đề xuất sửa ${f.label}`}
                            checked={!!f.proposal?.editable}
                            data-testid={`${testIdPrefix}-schema-proposal-${f.key}`}
                            onChange={e => updateProposal(f.key, e.target.checked)}
                          />
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
            <div className={schemaStyles.footer}>
              <div className={schemaStyles.footerActions}>
                <Button variant="secondary" onClick={onClose}>Hủy</Button>
                <Button
                  variant="primary"
                  disabled={saving}
                  data-testid={`${testIdPrefix}-schema-save`}
                  onClick={() => void handleSave()}
                >
                  {saving ? 'Đang lưu…' : 'Lưu cấu hình'}
                </Button>
              </div>
            </div>
          </>
        )}
      </div>
    </Modal>
  );
};
